'use client'
import { useEffect, useState } from 'react'
import { supabase } from '../lib/supabase'

interface Seat {
  id: number
  table_number: number
  seat_number: number
  guest_name: string
}

export default function Home() {
  const [seats, setSeats] = useState<Seat[]>([])
  const [selected, setSelected] = useState<Seat | null>(null)
  const [search, setSearch] = useState('')

  const tables = seats.reduce((acc: any, seat) => {
  if (!acc[seat.table_number]) acc[seat.table_number] = []
  acc[seat.table_number].push(seat)
  return acc
}, {})

  useEffect(() => {
    fetchSeats()
  }, [])

  async function fetchSeats() {
    const { data } = await supabase.from('seats').select('*').order('id').order('table_number')
    .order('seat_number')
    setSeats(data || [])
  }

  async function updateSeat(id: number, name: string) {
  await supabase
    .from('seats')
    .update({ guest_name: name })
    .eq('id', id)

  fetchSeats()
}

  async function clearAll() {
  if (!confirm('Clear all seats?')) return

  await supabase
    .from('seats')
    .update({ guest_name: '' })
    .neq('id', -1)

  fetchSeats()
}

  const SeatCircle = ({ seat }: { seat: Seat }) => {
  const match = seat.guest_name
    .toLowerCase()
    .includes(search.toLowerCase())

  return (
    <div
      onClick={() => setSelected(seat)}
      className={`h-12 rounded-lg flex items-center justify-center text-[10px] border cursor-pointer text-center px-1
      ${seat.guest_name ? 'bg-green-200' : 'bg-gray-100'}
      ${match && search ? 'ring-2 ring-yellow-400' : ''}`}
    >
      {seat.guest_name || `S${seat.seat_number}`}
    </div>
  )
}

  return (
    <div className="p-4 max-w-md mx-auto">
      <h1 className="text-xl font-bold mb-2">Wedding Seating</h1>

      <input
        placeholder="Search guest..."
        value={search}
        onChange={(e) => setSearch(e.target.value)}
        className="w-full p-2 mb-3 border rounded"
      />

      <button onClick={clearAll} className="mb-4 text-sm text-red-500">
        Clear All
      </button>

      <div className="flex flex-col gap-6">
  {Object.entries(tables).map(([tableNumber, tableSeats]: any) => (
    <div key={tableNumber} className="bg-white p-3 rounded shadow">
      
      <h2 className="text-sm font-bold mb-2">
        Table {tableNumber}
      </h2>

      <div className="grid grid-cols-5 gap-2">
        {tableSeats.map((seat: Seat) => (
          <SeatCircle key={seat.id} seat={seat} />
        ))}
      </div>

    </div>
  ))}
</div>

      {selected && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center">
          <div className="bg-white p-4 rounded">
            <h2 className="mb-2">Seat {selected.id}</h2>
            <input
              defaultValue={selected.guest_name}
              onBlur={(e) => {
                updateSeat(selected.id, e.target.value)
                setSelected(null)
              }}
              className="border p-2"
              autoFocus
            />
            <button onClick={() => setSelected(null)} className="ml-2">
              Close
            </button>
          </div>
        </div>
      )}
    </div>
  )
}